#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long H, x, y, C;
        scanf("%lld %lld %lld %lld", &H, &x, &y, &C);
        long long per = x + y / 2; // integer division gives floor(y/2)
        long long total = H * per;
        if (total <= C) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

